import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getInstitution, getInstitutionStudents, getInstitutionMentors, assignMentor } from '../api/client';

export default function InstitutionDetail() {
  const { id } = useParams();
  const [inst, setInst] = useState(null);
  const [students, setStudents] = useState([]);
  const [mentors, setMentors] = useState([]);
  const [msg, setMsg] = useState('');

  const load = async () => {
    try {
      const [{ data: instData }, { data: studs }, { data: mtr }] = await Promise.all([
        getInstitution(id),
        getInstitutionStudents(id),
        getInstitutionMentors(id),
      ]);
      setInst(instData);
      setStudents(studs);
      setMentors(mtr);
    } catch (e) {
      setMsg('❌ ' + JSON.stringify(e.response?.data || e.message));
    }
  };

  useEffect(() => { load(); }, [id]);

  const handleAssignMentor = async (studentId, mentorId) => {
    try {
      await assignMentor(id, studentId, mentorId);
      setMsg('✅ Mentor assigned');
      load();
    } catch (e) {
      setMsg('❌ ' + JSON.stringify(e.response?.data || e.message));
    }
  };

  return (
    <div>
      <div className="page-header">
        <h2>Institution: {inst ? inst.name : id}</h2>
      </div>

      {msg && <div className={`alert ${msg.startsWith('✅') ? 'alert-success' : 'alert-error'}`}>{msg}</div>}

      <div style={{ display:'flex', gap:20 }}>
        <div style={{ flex:1 }}>
          <h3>Students</h3>
          <div className="table-wrap">
            <table>
              <thead><tr><th>#</th><th>Username</th><th>Email</th><th>Reg#</th><th>Mentor</th><th>Action</th></tr></thead>
              <tbody>
                {students.map((s,i) => (
                  <tr key={s.id}>
                    <td>{i+1}</td>
                    <td>{s.username}</td>
                    <td>{s.email}</td>
                    <td>{s.institutional_registration_number || '-'}</td>
                    <td>{s.roles?.join(', ')}</td>
                    <td>
                      <select onChange={e => handleAssignMentor(s.id, Number(e.target.value))} defaultValue="">
                        <option value="">Assign mentor</option>
                        {mentors.map(m => <option key={m.id} value={m.id}>{m.username || m.email}</option>)}
                      </select>
                    </td>
                  </tr>
                ))}
                {students.length === 0 && <tr><td colSpan={6} style={{ textAlign:'center', padding:20 }}>No students.</td></tr>}
              </tbody>
            </table>
          </div>
        </div>

        <div style={{ width:360 }}>
          <h3>Mentors</h3>
          <div className="table-wrap">
            <table>
              <thead><tr><th>#</th><th>Username</th><th>Email</th></tr></thead>
              <tbody>
                {mentors.map((m,i) => (
                  <tr key={m.id}><td>{i+1}</td><td>{m.username}</td><td>{m.email}</td></tr>
                ))}
                {mentors.length === 0 && <tr><td colSpan={3} style={{ textAlign:'center', padding:20 }}>No mentors.</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}
